 19	
 20	import { tickLabels } from '../ChartLabels/styleOverrides';
 21	import ComponentReady from '../ComponentReady/ComponentReady';
 22	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 23	import { getUtilizationQueries } from '../utils/queries';
 24	import {
 25	  findMaxYValue,
 26	  formatMemoryYTick,
 27	  getPrometheusData,
 28	  MILLISECONDS_MULTIPLIER,
 29	  queriesToLink,
 30	  tickFormat,
 31	  TICKS_COUNT,
 32	} from '../utils/utils';
 33	
 34	type MigrationThresholdChartDiskRateProps = {
 35	  vmi: V1VirtualMachineInstance;
 36	};
 37	
 38	const MigrationThresholdChartDiskRate: React.FC<MigrationThresholdChartDiskRateProps> = ({
 39	  vmi,
 40	}) => {
 41	  const { t } = useKubevirtTranslation();
 42	  const { currentTime, duration, timespan } = useDuration();
 43	  const queries = useMemo(() => getUtilizationQueries({ duration, obj: vmi }), [vmi, duration]);
 44	  const { height, ref, width } = useResponsiveCharts();
 45	
 46	  const [diskRate] = usePrometheusPoll({
 47	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 48	    endTime: currentTime,
 49	    namespace: vmi?.metadata?.namespace,
 50	    query: queries?.MIGRATION_DISK_TRANSFER_RATE,
 51	    timespan,
 52	  });
 53	  const dataProcessed = useMemo(() => getPrometheusData(diskRate), [diskRate]);
 54	
 55	  const chartDataProcessed = dataProcessed?.map(([x, y]) => {
 56	    return { name: t('Data Processed'), x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 57	  });
 58	
 59	  const isReady = !isEmpty(chartDataProcessed);
 60	  const yMax = findMaxYValue(chartDataProcessed);
 61	  const linkToMetrics = queriesToLink(queries.MIGRATION_DISK_TRANSFER_RATE);
 62	  return (
 63	    <ComponentReady isReady={isReady} linkToMetrics={linkToMetrics}>
 64	      <div className="util-threshold-chart" ref={ref}>
 65	        <Link to={linkToMetrics}>
 66	          <Chart
 67	            containerComponent={
 68	              <ChartVoronoiContainer
 69	                labels={({ datum }) => {
 70	                  return `${datum?.name}: ${xbytes(datum?.y, { fixed: 2, iec: true })}`;
 71	                }}
 72	                constrainToVisibleArea
 73	              />
 74	            }
 75	            domain={{
 76	              x: [currentTime - timespan, currentTime],
 77	              y: [0, yMax],
 78	            }}
 79	            height={height}
 80	            padding={35}
 81	            scale={{ x: 'time', y: 'linear' }}
 82	            width={width}
 83	          >
 84	            <ChartAxis
 85	              style={{
 86	                grid: {
 87	                  stroke: chart_color_black_200.value,
 88	                },
 89	                tickLabels,
 90	              }}
 91	              dependentAxis
 92	              tickFormat={formatMemoryYTick(yMax, 2)}
 93	              tickValues={[0, yMax]}
 94	            />
 95	            <ChartAxis
 96	              style={{
 97	                tickLabels: { padding: 2, ...tickLabels },
 98	                ticks: { stroke: 'transparent' },
 99	              }}
100	              axisComponent={<></>}
101	              tickCount={TICKS_COUNT}
102	              tickFormat={tickFormat(duration, currentTime)}
103	            />
104	            <ChartGroup>
105	              <ChartArea
106	                style={{
107	                  data: {
108	                    stroke: chart_color_blue_300.value,
109	                  },
110	                }}
111	                data={chartDataProcessed}
112	              />
113	            </ChartGroup>
114	          </Chart>
115	        </Link>
116	      </div>
117	    </ComponentReady>
118	  );
119	};
120	
121	export default MigrationThresholdChartDiskRate;

